import itertools,base64,string
s='ZmxhZaswbhjNidDFMISOGQhW=='
# include possibility that there is 1 missing char before == from OCR space
maps={
'a':'a3','s':'s57','N':'Nn','I':'Il1','O':'O0o','G':'G6C','Q':'Q0O','S':'S5','D':'D0O','b':'b6h','h':'hn','j':'ji','M':'MN','w':'wv'}
opts=[]
for ch in s:
    opts.append(maps.get(ch,ch))
count=0
for prod in itertools.product(*opts):
    cand=''.join(prod)
    try:
        dec=base64.b64decode(cand,validate=True)
    except: 
        continue
    if all(32<=c<127 for c in dec):
        txt=dec.decode('ascii','ignore')
        if 'flag{' in txt or txt.startswith('flag') or '{' in txt:
            print(cand,txt)
            break
    count+=1
else:
    print('none')
